@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
* {
  box-sizing: border-box;
  font-family: "Figtree", sans-serif;
  margin: 0;
  padding: 0;
}

.card {
  background: #fff;
  border-radius: 10px;
  padding: 24px 28px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 40px;
}

.left {
  display: flex;
  align-items: center;
  gap: 18px;
}

.avatar {
  width: 60px;
  height: 60px;
  border-radius: 50%;
  background: #469BC0;
  color: #fff;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 21px;
  font-weight: 700;
  flex-shrink: 0;
}

.greeting {
  font-size: 22px;
  font-weight: 700;
  color: #05042E;
  margin-bottom: 4px;
}

.datetime {
  font-size: 14px;
  font-weight: 500;
  color: #888780;
}

.right {
  display: flex;
  align-items: center;
  gap: 32px;
}

.info-block {
  display: flex;
  flex-direction: column;
  gap: 6px;
  align-items: flex-start;
  min-width: 90px;
}

.info-label {
  font-size: 11px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  line-height: 1;
}

.info-value {
  font-size: 15px;
  font-weight: 600;
  color: #05042E;
  line-height: 1;
  height: 22px;
  display: flex;
  align-items: center;
}

.role-badge {
  font-size: 12px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.03em;
  padding: 0 12px;
  height: 22px;
  border-radius: 20px;
  display: inline-flex;
  align-items: center;
}

.role-admin {
  background: #E3EFF6;
  color: #1B4F6C;
}

.role-manager {
  background: #E1F5EE;
  color: #085041;
}

.role-technician {
  background: #FAEEDA;
  color: #633806;
}

.role-viewer {
  background: rgba(5, 4, 46, 0.06);
  color: #05042E;
}

.divider {
  width: 0.5px;
  height: 40px;
  background: rgba(0, 0, 0, 0.08);
}

.signout-btn {
  height: 40px;
  padding: 0 20px;
  border-radius: 6px;
  border: none;
  cursor: pointer;
  background: rgba(5, 4, 46, 0.06);
  color: #05042E;
  font-family: "Figtree", sans-serif;
  font-size: 14px;
  font-weight: 700;
  white-space: nowrap;
}

.signout-btn:hover {
  background: #fee2e2;
  color: #991b1b;
}

