function initials(name) {
  if (!name) return '--';
  var parts = name.trim().split(' ');
  return parts.length >= 2 ? (parts[0][0] + parts[parts.length - 1][0]).toUpperCase() : parts[0].substring(0, 2).toUpperCase();
}
function fmtLastLogin(d) {
  if (!d) return 'First login';
  var dt = new Date(d);
  if (isNaN(dt.getTime())) return '—';
  return dt.toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  }) + ' at ' + dt.toLocaleTimeString('en-GB', {
    hour: '2-digit',
    minute: '2-digit'
  });
}
function fmtNow() {
  var now = new Date();
  return now.toLocaleDateString('en-GB', {
    weekday: 'long',
    day: '2-digit',
    month: 'long',
    year: 'numeric'
  }) + ' · ' + now.toLocaleTimeString('en-GB', {
    hour: '2-digit',
    minute: '2-digit'
  });
}
function roleClass(role) {
  var map = {
    admin: 'role-admin',
    manager: 'role-manager',
    technician: 'role-technician',
    viewer: 'role-viewer'
  };
  return map[(role || '').toLowerCase()] || 'role-viewer';
}
function render(model) {
  var m = model || {};
  var name = m.userName || 'User';
  var role = m.userRole || 'viewer';
  var lastLogin = m.userLastLogin;
  var hour = new Date().getHours();
  var greetingWord = hour < 12 ? 'Good morning' : hour < 18 ? 'Good afternoon' : 'Good evening';
  document.getElementById('avatar').textContent = initials(name);
  document.getElementById('greeting').textContent = greetingWord + ', ' + name.split(' ')[0];
  document.getElementById('datetime').textContent = fmtNow();
  var roleBadge = document.getElementById('role_badge');
  roleBadge.textContent = role;
  roleBadge.className = 'role-badge ' + roleClass(role);
  document.getElementById('last_login').textContent = fmtLastLogin(lastLogin);
}
function initWhenReady() {
  if (typeof appsmith === 'undefined' || !appsmith.onReady) {
    setTimeout(initWhenReady, 50);
    return;
  }
  appsmith.onReady(function () {
    render(appsmith.model);
    document.getElementById('signout_btn').addEventListener('click', function () {
      appsmith.triggerEvent('onSignOut');
    });
    appsmith.onModelChange(function (model) {
      render(model);
    });
    setInterval(function () {
      document.getElementById('datetime').textContent = fmtNow();
    }, 60000);
  });
}
initWhenReady();

